<?php
require __DIR__.'/../inc/bootstrap.php';admin_required();ensure_pages_table();$pages=db()->query('SELECT * FROM pages ORDER BY updated_at DESC')->fetchAll();
$pageTitle='Sayfalar';$activeMenu='pages';require __DIR__.'/_header.php';
function page_actions(string $edit,string $view,bool $deletable=false,int $id=0): string {
    $html='<div class="actions"><a class="icon-btn" href="'.e($edit).'" title="Düzenle" aria-label="Düzenle">✎</a><a class="icon-btn" href="'.e($view).'" target="_blank" title="Görüntüle" aria-label="Görüntüle">↗</a>';
    if($deletable)$html.='<form method="post" action="page-delete.php" onsubmit="return confirm(\'Bu sayfa kalıcı olarak silinsin mi?\')"><input type="hidden" name="csrf" value="'.csrf().'"><input type="hidden" name="id" value="'.$id.'"><button class="icon-btn danger" title="Sil" aria-label="Sil">⌫</button></form>';
    else $html.='<span class="icon-btn locked" title="Yerleşik sayfa silinemez" aria-label="Silinemez">♙</span>';
    return $html.'</div>';
}
?><div class="page-head"><div><h1>Tüm Sayfalar</h1><p>2 yerleşik sayfa ve eklediğin özel sayfalar</p></div><a class="btn" href="page-edit.php">Sayfa Ekle</a></div><section class="card"><div class="table-wrap"><table><thead><tr><th>Başlık</th><th>Adres</th><th>Tür</th><th>Durum</th><th>İşlemler</th></tr></thead><tbody><tr><td><strong>Ana Sayfa</strong></td><td>/index.php</td><td>Yerleşik sayfa</td><td><span class="badge">Yayında</span></td><td><?=page_actions('settings.php','../index.php')?></td></tr><tr><td><strong>İletişim</strong></td><td>/iletisim.php</td><td>Yerleşik sayfa</td><td><span class="badge">Yayında</span></td><td><?=page_actions('settings.php','../iletisim.php')?></td></tr><?php foreach($pages as $p):?><tr><td><strong><?=e($p['title'])?></strong></td><td>/page.php?slug=<?=e($p['slug'])?></td><td>Özel sayfa</td><td><span class="badge <?=!$p['is_published']?'draft':''?>"><?=$p['is_published']?'Yayında':'Taslak'?></span></td><td><?=page_actions('page-edit.php?id='.(int)$p['id'],'../page.php?slug='.rawurlencode($p['slug']),true,(int)$p['id'])?></td></tr><?php endforeach?></tbody></table></div></section><?php require __DIR__.'/_footer.php';?>
